// Normalized data model for a real-time chat app
const dataModel = {
  users: {
    byId: {
      'u1': { id: 'u1', name: 'Alice' },
      'u2': { id: 'u2', name: 'Bob' },
    },
    allIds: ['u1', 'u2'],
  },
  messages: {
    byId: {},
    allIds: [],
  },
};

function addMessage(model, message) {
  const newMessagesById = { ...model.messages.byId, [message.id]: message };
  const newMessagesAllIds = [...model.messages.allIds, message.id];

  return {
    ...model,
    messages: {
      byId: newMessagesById,
      allIds: newMessagesAllIds,
    },
  };
}

// Example usage:
const newMessage = { id: 'm1', userId: 'u1', text: 'Hello, world!', timestamp: Date.now() };
const updatedModel = addMessage(dataModel, newMessage);
console.log(updatedModel.messages);

