def is_prime(n):
    if n <= 1:
        return False
    for i in range(2, n):
        if n % i == 0:
            return False
    return True

def sum_primes(limit):
    total = 0
    for num in range(limit):
        if is_prime(num):
            total += num
    return total

print(sum_primes(10000))

import math

def is_prime_optimized(n):
    if n <= 1:
        return False
    for i in range(2, int(math.sqrt(n)) + 1):
        if n % i == 0:
            return False
    return True

def sum_primes_optimized(limit):
    total = 0
    for num in range(limit):
        if is_prime_optimized(num):
            total += num
    return total

print(sum_primes_optimized(10000))
